import { useEffect, useState } from 'react'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { motion } from 'framer-motion'
import { useAuthStore } from '@/store/useAuthStore'
import { loadVerbs, recordVerbAttempt, TENSE_LABEL, PERSON_LABEL, PERSON_DE, hasUsableTense, pickRandomPerson, PERSONS, type Tense, type Person, type VerbRow } from '@/lib/verbs'
import { awardXp } from '@/lib/xp'
import { Header } from '@/components/Header'
import { XPToast, type XpToastData } from '@/components/XPToast'
import { ScoreScreen } from '@/components/ScoreScreen'

// 7b — MC Konjugation: 4 Optionen, eine korrekt. +8 XP korrekt, 0 falsch.

const ROUND_SIZE = 10

type Question = { verb: VerbRow; tense: Tense; person: Person; correct: string; options: string[] }

function shuffle<T>(a: T[]): T[] { const c = [...a]; for (let i = c.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [c[i], c[j]] = [c[j], c[i]] } return c }

export default function MultipleChoice() {
  const { user } = useAuthStore()
  const navigate = useNavigate()
  const [params] = useSearchParams()
  const tense = (params.get('tense') ?? 'present_indefinite') as Tense

  const [verbs, setVerbs] = useState<VerbRow[] | null>(null)
  const [round, setRound] = useState<Question[]>([])
  const [step, setStep] = useState(0)
  const [picked, setPicked] = useState<number | null>(null)
  const [stats, setStats] = useState({ correct: 0, wrong: 0, totalXp: 0, mastered: [] as string[] })
  const [done, setDone] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false
    async function load() {
      try {
        const v = await loadVerbs()
        if (cancelled) return
        const usable = v.filter((x) => hasUsableTense(x, tense))
        if (usable.length === 0) { setError(`Keine Verben für ${TENSE_LABEL[tense]}.`); return }
        setVerbs(usable)
        startRound(usable)
      } catch (e) { setError(String((e as Error).message ?? e)) }
    }
    void load()
    return () => { cancelled = true }
  }, [tense])

  function startRound(pool: VerbRow[]) {
    const qs: Question[] = []
    while (qs.length < ROUND_SIZE) {
      const v = pool[Math.floor(Math.random() * pool.length)]
      const p = pickRandomPerson(v, tense)
      if (!p) continue
      const correct = v.conjugations![tense][p]!
      // Distraktoren: gleicher Tempus, andere Personen oder andere Verben
      const distractors = new Set<string>()
      let attempts = 0
      while (distractors.size < 3 && attempts < 50) {
        attempts++
        const dv = pool[Math.floor(Math.random() * pool.length)]
        const dp = PERSONS[Math.floor(Math.random() * PERSONS.length)]
        const form = dv.conjugations?.[tense]?.[dp]
        if (form && form !== correct) distractors.add(form)
      }
      if (distractors.size < 3) continue
      const options = shuffle([correct, ...distractors])
      qs.push({ verb: v, tense, person: p, correct, options })
    }
    setRound(qs); setStep(0); setPicked(null); setStats({ correct: 0, wrong: 0, totalXp: 0, mastered: [] }); setDone(false)
  }

  function handlePick(i: number) {
    if (picked !== null || !user || done) return
    const q = round[step]
    setPicked(i)
    const isCorrect = q.options[i] === q.correct
    const xp = isCorrect ? 8 : 0
    if (xp > 0) {
      void awardXp({ baseAmount: xp, source: 'verb_mc_correct', mode: 'medical' }).then((r) => r && setToast({ id: Date.now(), ...r }))
    }
    void recordVerbAttempt(user.id, q.verb.id, q.tense, isCorrect).then((r) => {
      if (r.justMastered) {
        setStats((s) => ({ ...s, mastered: [...s.mastered, `${q.verb.infinitive} (${TENSE_LABEL[q.tense]})`] }))
        void awardXp({ baseAmount: 75, source: 'verb_mastered', mode: 'medical' })
      }
    })
    setStats((s) => ({ ...s, correct: s.correct + (isCorrect ? 1 : 0), wrong: s.wrong + (isCorrect ? 0 : 1), totalXp: s.totalXp + xp }))
    setTimeout(() => {
      if (step + 1 >= ROUND_SIZE) { setDone(true) }
      else { setStep(step + 1); setPicked(null) }
    }, 700)
  }

  useEffect(() => { if (toast) { const t = setTimeout(() => setToast(null), 1200); return () => clearTimeout(t) } }, [toast])

  if (error) return <Wrap><Status>⚠ {error}</Status><Back nav={navigate} /></Wrap>
  if (!verbs || round.length === 0) return <Wrap><Status>Wird geladen…</Status></Wrap>
  if (done) {
    return (
      <ScoreScreen
        emoji={stats.correct >= 8 ? '🎉' : '⚡'}
        title={`${stats.correct} / ${ROUND_SIZE} richtig`}
        subtitle={stats.mastered.length > 0 ? `Neu gemeistert: ${stats.mastered.join(', ')}` : undefined}
        stats={[{ label: 'Richtig (×8)', value: stats.correct, highlight: true }, { label: 'Falsch', value: stats.wrong }]}
        totalXp={stats.totalXp + stats.mastered.length * 75}
        primaryAction={{ label: 'Nochmal', onClick: () => verbs && startRound(verbs) }}
        secondaryAction={{ label: 'Zurück', onClick: () => navigate('/learn/medical/verb-trainer') }}
      />
    )
  }

  const q = round[step]

  return (
    <Wrap>
      <div style={{ width: '100%', maxWidth: 480, fontSize: '0.85rem', opacity: 0.65, marginBottom: '0.4rem' }}>{step + 1} / {ROUND_SIZE} · {TENSE_LABEL[tense]}</div>
      <div style={{ width: '100%', maxWidth: 480, background: 'var(--white)', border: '2px solid var(--red)', borderRadius: 14, padding: '1.5rem 1rem', textAlign: 'center', boxShadow: 'var(--shadow-card)' }}>
        <div style={{ fontSize: '0.75rem', opacity: 0.55, letterSpacing: '0.5px', marginBottom: 6 }}>{PERSON_DE[q.person]} · {PERSON_LABEL[q.person]}</div>
        <div className="hu-vocab" style={{ color: 'var(--red)', fontSize: '2rem' }}>{q.verb.infinitive}</div>
        <div style={{ fontSize: '0.85rem', opacity: 0.6, fontStyle: 'italic', marginTop: 4 }}>{q.verb.infinitive_de}</div>
      </div>
      <div style={{ width: '100%', maxWidth: 480, marginTop: '0.9rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
        {q.options.map((opt, i) => {
          const correct = picked !== null && opt === q.correct
          const wrongPick = picked === i && opt !== q.correct
          const bg = correct ? 'var(--green)' : wrongPick ? 'var(--red)' : 'var(--white)'
          const color = correct || wrongPick ? 'var(--cream)' : 'inherit'
          const border = correct ? 'var(--green)' : wrongPick ? 'var(--red)' : 'rgba(0,0,0,0.15)'
          return (
            <motion.button key={i} animate={wrongPick ? { x: [0, -5, 5, -5, 5, 0] } : {}} transition={{ duration: 0.35 }} onClick={() => handlePick(i)} disabled={picked !== null} style={{ background: bg, color, border: `2px solid ${border}`, padding: '0.85rem', borderRadius: 12, fontFamily: 'Georgia, serif', fontSize: '0.95rem', fontWeight: 700, cursor: picked !== null ? 'default' : 'pointer', minHeight: 60 }}>
              {opt}
            </motion.button>
          )
        })}
      </div>
      <Back nav={navigate} />
      <XPToast toast={toast} />
    </Wrap>
  )
}

function Wrap({ children }: { children: React.ReactNode }) { return (<div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}><Header /><main style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '1.5rem 1rem 3rem' }}>{children}</main></div>) }
function Status({ children }: { children: React.ReactNode }) { return <div style={{ opacity: 0.55, marginTop: '20vh' }}>{children}</div> }
function Back({ nav }: { nav: ReturnType<typeof useNavigate> }) { return <button onClick={() => nav('/learn/medical/verb-trainer')} style={{ marginTop: '1.5rem', background: 'none', border: '1.5px solid rgba(0,0,0,0.15)', padding: '0.45rem 0.9rem', borderRadius: 8, fontFamily: 'inherit', fontSize: '0.8rem', cursor: 'pointer', opacity: 0.65 }}>Sitzung abbrechen</button> }
